101	    _scrollController.dispose();
102	    super.dispose();
103	  }
104	
105	  void _onRefreshTick() {
106	    _fetchUsers(refresh: true);
107	  }
108	
109	  Future<void> _loadToken() async {
110	    final token = await ApiService.getToken();
111	    if (mounted) setState(() => _token = token);
112	  }
113	
114	  Future<void> _fetchUsers({bool refresh = false}) async {
115	    if (refresh) {
116	      setState(() {
117	        _page = 1;
118	        _users.clear();
119	        _hasMore = true;
120	      });
121	    }
122	    if (_isLoading || !_hasMore) return;
123	
124	    setState(() => _isLoading = true);
125	
126	    try {
127	      final queryParams = {
128	        'page': _page.toString(),
129	        'per_page': _perPage.toString(),
130	        if (_filterSex != null) 'sex': _filterSex!,
131	        if (_filterSexuality != null) 'sexuality': _filterSexuality!,
132	        'age_min': _filterAgeMin.toString(),
133	        'age_max': _filterAgeMax.toString(),
134	      };
135	
136	      final response = await http.get(
137	        Uri.parse('$_baseUrl/api/users').replace(queryParameters: queryParams),
138	        headers: {
139	          'Content-Type': 'application/json',
140	          if (_token != null) 'Authorization': 'Bearer $_token',
141	        },
142	      );
143	
144	      if (response.statusCode == 200) {
145	        final data = jsonDecode(response.body) as Map<String, dynamic>;
146	        final List<dynamic> userList = data['users'] as List<dynamic>;
147	
148	        final newUsers = userList
149	            .map((json) => UserCard.fromJson(json as Map<String, dynamic>))
150	            .toList();
151	
152	        setState(() {
153	          _users.addAll(newUsers);
154	          _hasMore = newUsers.length == _perPage;
155	          if (_hasMore) _page++;
156	        });
157	      } else {
158	        setState(() => _errorMessage = 'Failed to load users');
159	      }
160	    } catch (e) {
161	      setState(() => _errorMessage = 'Connection error');
162	    } finally {
163	      if (mounted) setState(() => _isLoading = false);
164	    }
165	  }
166	
