46	  factory _RankOneTimer.fromJson(Map<String, dynamic> json) {
47	    final lockedUser = (json['user'] as Map<String, dynamic>?) ??
48	        (json['locked_user'] as Map<String, dynamic>?) ??
49	        {};
50	    return _RankOneTimer(
51	      id: (json['rank_one_id'] as int?) ?? (json['id'] as int?) ?? 0,
52	      status: json['status'] as String? ?? 'pending',
53	      expiresAt: _parseUtc(json['expires_at'] as String),
54	      lockedUserId:
55	          (lockedUser['id'] as int?) ?? (json['liked_id'] as int?) ?? 0,
56	      lockedUsername: (lockedUser['username'] as String?) ?? '',
57	    );
58	  }
