61	DateTime _parseUtc(String s) {
62	  // Backend emits naive UTC ISO strings (no 'Z'/offset). Force UTC interpretation.
63	  final parsed = DateTime.parse(s);
64	  return parsed.isUtc ? parsed : DateTime.parse('${s}Z');
65	}
