150	      _wilChannel = channel;
151	      _wsSetConnected(true);
152	      _wilSub = channel.stream.listen(
153	        _onWilMessage,
154	        onError: (_) => _onWilClosed(),
155	        onDone: _onWilClosed,
156	        cancelOnError: true,
157	      );
158	    } catch (_) {
159	      _onWilClosed();
160	    }
161	  }
