178	    // Try to reconnect with exponential-ish backoff (capped).
179	    _wsReconnectAttempts++;
180	    final delaySeconds = (_wsReconnectAttempts * 2).clamp(2, 30);
181	    _wsReconnectTimer?.cancel();
