56	  Future<void> _load() async {
57	    setState(() { _isLoading = true; _error = null; });
58	    try {
59	      final prefs = await SharedPreferences.getInstance();
60	      final jwtToken = prefs.getString('jwt_token');
61	      final username = prefs.getString('username');
62	
63	      if (jwtToken == null) {
64	        setState(() { _error = 'Not logged in'; _isLoading = false; });
65	        return;
66	      }
67	
68	      final headers = {'Authorization': 'Bearer $jwtToken'};
69	
70	      final results = await Future.wait([
71	        http.get(Uri.parse('$_baseUrl/api/matches'), headers: headers),
72	        http.get(Uri.parse('$_baseUrl/api/stream-token'), headers: headers),
73	      ]);
74	
75	      final matchesRes = results[0];
76	      final streamRes = results[1];
77	
78	      if (matchesRes.statusCode != 200) {
79	        setState(() { _error = 'Failed to load matches (${matchesRes.statusCode})'; _isLoading = false; });
80	        return;
81	      }
82	
83	      final matchesData = jsonDecode(matchesRes.body) as Map<String, dynamic>;
84	      // API returns {"users": [...]} not {"matches": [...]}
85	      final matches = (matchesData['users'] as List<dynamic>? ?? []).cast<Map<String, dynamic>>();
86	
87	      String? streamToken;
88	      if (streamRes.statusCode == 200) {
89	        final streamData = jsonDecode(streamRes.body) as Map<String, dynamic>;
90	        streamToken = streamData['token'] as String?;
91	      }
92	
93	      final newIds = matches.map((m) => m['id'] as int? ?? 0).toSet();
94	      final newMatchesDetected =
95	          _knownMatchIds.isNotEmpty && newIds.difference(_knownMatchIds).isNotEmpty;
96	      _knownMatchIds = newIds;
97	
98	      setState(() {
99	        _matches = matches;
100	        _streamToken = streamToken;
101	        _currentUsername = username;
102	        _isLoading = false;
103	      });
104	
105	      if (newMatchesDetected) {
106	        WidgetsBinding.instance.addPostFrameCallback((_) {
107	          if (_scrollController.hasClients) {
108	            _scrollController.animateTo(
109	              _scrollController.position.maxScrollExtent,
110	              duration: const Duration(milliseconds: 400),
111	              curve: Curves.easeOut,
112	            );
113	          }
114	        });
115	      }
116	    } catch (e) {
117	      setState(() { _error = 'Error: $e'; _isLoading = false; });
118	    }
119	  }
