50	        lockId: json['lock_id'] is int ? json['lock_id'] as int : (json['lock_id'] != null ? int.tryParse(json['lock_id'].toString()) : null),
51	        lockedAt: json['locked_at'] != null ? _parseUtc(json['locked_at'].toString()) : null,
