import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';
import '../services/auth_service.dart';
import '../services/api_service.dart';
import 'main_screen.dart';

class ConfirmScreen extends StatefulWidget {
  final String username;
  final String password;
  final DateTime dob;
  final String sex;

  const ConfirmScreen({super.key, required this.username, required this.password, required this.dob, required this.sex});

  @override
  State<ConfirmScreen> createState() => _ConfirmScreenState();
}

class _ConfirmScreenState extends State<ConfirmScreen> {
  bool _isLoading = false;
  String _error = '';

  String _formatDate(DateTime date) =>
      '${date.day.toString().padLeft(2, '0')}/${date.month.toString().padLeft(2, '0')}/${date.year}';

  int get _age {
    final now = DateTime.now();
    int age = now.year - widget.dob.year;
    if (now.month < widget.dob.month ||
        (now.month == widget.dob.month && now.day < widget.dob.day)) age--;
    return age;
  }

  void _createAccount() async {
    setState(() { _isLoading = true; _error = ''; });

    final result = await ApiService.register(
      widget.username,
      widget.password,
      age: _age,
      sex: widget.sex,
    );

    if (result['success'] == true) {
      final token = await AuthService().login(widget.username, widget.password);
      if (token != null) {
        final prefs = await SharedPreferences.getInstance();
        await prefs.setString('username', widget.username);
        if (mounted) {
          Navigator.of(context).pushAndRemoveUntil(
            MaterialPageRoute(builder: (_) => const MainScreen()),
            (route) => false,
          );
        }
      } else {
        setState(() { _isLoading = false; _error = 'Account created but login failed.'; });
      }
    } else {
      setState(() {
        _isLoading = false;
        _error = (result['message'] as String?) ?? 'Registration failed. Please try again.';
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Confirm Details'),
        leading: const BackButton(color: Colors.white),
      ),
      body: SafeArea(
        child: Padding(
          padding: const EdgeInsets.all(28.0),
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              const Spacer(),
              Container(
                width: 90,
                height: 90,
                decoration: BoxDecoration(
                  color: Colors.blueAccent.withOpacity(0.15),
                  shape: BoxShape.circle,
                  border: Border.all(color: Colors.blueAccent.withOpacity(0.5), width: 2),
                ),
                child: const Icon(Icons.check_circle_outline, size: 50, color: Colors.blueAccent),
              ),
              const SizedBox(height: 24),
              const Text('Almost there!',
                  style: TextStyle(fontSize: 26, fontWeight: FontWeight.bold, color: Colors.white)),
              const SizedBox(height: 6),
              const Text('Confirm your details below',
                  style: TextStyle(fontSize: 14, color: Colors.grey)),
              const SizedBox(height: 40),
              _detailRow(Icons.person_outline, 'Username', widget.username),
              const SizedBox(height: 12),
              _detailRow(Icons.cake_outlined, 'Date of Birth', _formatDate(widget.dob)),
              const SizedBox(height: 12),
              _detailRow(Icons.calendar_today_outlined, 'Age', '$_age years old'),
              const SizedBox(height: 12),
              _detailRow(Icons.person_outline, 'Sex', widget.sex),
              const SizedBox(height: 32),
              if (_error.isNotEmpty)
                Padding(
                  padding: const EdgeInsets.only(bottom: 16),
                  child: Text(_error, style: const TextStyle(color: Colors.redAccent)),
                ),
              SizedBox(
                width: double.infinity,
                child: ElevatedButton(
                  onPressed: _isLoading ? null : _createAccount,
                  child: _isLoading
                      ? const SizedBox(height: 20, width: 20,
                          child: CircularProgressIndicator(color: Colors.white, strokeWidth: 2))
                      : const Text('Create My Account'),
                ),
              ),
              const Spacer(),
            ],
          ),
        ),
      ),
    );
  }

  Widget _detailRow(IconData icon, String label, String value) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 14),
      decoration: BoxDecoration(
        color: const Color(0xFF1E1E2E),
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: const Color(0xFF3A3A5E)),
      ),
      child: Row(
        children: [
          Icon(icon, color: Colors.blueAccent, size: 20),
          const SizedBox(width: 12),
          Text(label, style: const TextStyle(color: Colors.grey, fontSize: 14)),
          const Spacer(),
          Text(value, style: const TextStyle(color: Colors.white, fontWeight: FontWeight.w600, fontSize: 15)),
        ],
      ),
    );
  }
}

