import 'dart:io';
import 'package:flutter/foundation.dart';

class BaseConfig {
  static const String _prodHost = 'api.datetris.date';

  /// The server IP for real devices in debug builds (when useEmulatorIP is false).
  /// Update this to match your development machine's local IP.
  static const String realDeviceIp = '10.205.239.199';

  /// Set to true when running on Android Emulator or iOS Simulator (debug only).
  /// Set to false when running on real devices in debug (or change the IP above).
  static const bool useEmulatorIP = true;

  static String get baseUrl {
    if (kReleaseMode) {
      return 'https://$_prodHost';
    }

    if (kIsWeb) {
      return 'http://0.0.0.0:8000';
    }

    if (Platform.isAndroid) {
      return 'http://10.0.2.2:8000';
    } else if (Platform.isIOS) {
      return 'http://localhost:8000';
    }

    return 'http://10.0.2.2:8000';
  }

  static String get wsUrl {
    if (kReleaseMode) {
      return 'wss://$_prodHost';
    }

    if (kIsWeb) {
      return 'ws://localhost:8000';
    }

    if (Platform.isAndroid) {
      return useEmulatorIP ? 'ws://10.0.2.2:8000' : 'ws://$realDeviceIp:8000';
    } else if (Platform.isIOS) {
      return useEmulatorIP ? 'ws://localhost:8000' : 'ws://$realDeviceIp:8000';
    }

    return 'ws://$realDeviceIp:8000';
  }
}

