import 'dart:async';
import 'package:flutter/material.dart';
import 'package:date_picker_plus/date_picker_plus.dart';
import 'package:shared_preferences/shared_preferences.dart';
import '../services/api_service.dart';
import '../services/auth_service.dart';
import 'main_screen.dart';

class RegistrationScreen extends StatefulWidget {
  const RegistrationScreen({super.key});

  @override
  State<RegistrationScreen> createState() => _RegistrationScreenState();
}

class _RegistrationScreenState extends State<RegistrationScreen> {
  static const _bg = Color(0xFF0E0E0E);
  static const _fieldFill = Color(0xFF2A2A2A);

  static const _sexOptions = [
    'Male', 'Female', 'Transgender Female', 'Transgender Male', 'Not Specified',
  ];
  static const _sexualities = [
    'Straight', 'Gay', 'Bisexual', 'Pansexual', 'Not Specified',
  ];
  static const _starSigns = [
    'Aries', 'Taurus', 'Gemini', 'Cancer', 'Leo', 'Virgo',
    'Libra', 'Scorpio', 'Sagittarius', 'Capricorn', 'Aquarius', 'Pisces',
  ];

  // Controllers
  final _usernameController = TextEditingController();
  final _passwordController = TextEditingController();
  final _heightController = TextEditingController();
  final _headlineController = TextEditingController();
  final _bioController = TextEditingController();

  // Picker values
  DateTime? _dob;
  String? _sex;
  String? _sexuality;
  String? _starSign;

  // Username availability
  String _usernameError = '';
  bool _usernameAvailable = false;
  bool _checkingUsername = false;
  Timer? _debounce;

  String _passwordError = '';
  String _generalError = '';
  bool _submitting = false;

  DateTime get _maxDob {
    final now = DateTime.now();
    return DateTime(now.year - 18, now.month, now.day);
  }

  DateTime get _minDob {
    final now = DateTime.now();
    return DateTime(now.year - 100, now.month, now.day);
  }

  int get _age {
    if (_dob == null) return 0;
    final now = DateTime.now();
    int a = now.year - _dob!.year;
    if (now.month < _dob!.month ||
        (now.month == _dob!.month && now.day < _dob!.day)) a--;
    return a;
  }

  @override
  void dispose() {
    _debounce?.cancel();
    _usernameController.dispose();
    _passwordController.dispose();
    _heightController.dispose();
    _headlineController.dispose();
    _bioController.dispose();
    super.dispose();
  }

  void _onUsernameChanged(String value) {
    if (_debounce?.isActive ?? false) _debounce!.cancel();
    setState(() {
      _usernameAvailable = false;
      _usernameError = '';
    });
    final v = value.trim();
    if (v.toLowerCase().contains('jason')) {
      setState(() => _usernameError = 'Username not allowed');
      return;
    }
    if (v.length < 3) {
      setState(() => _usernameError = v.isEmpty ? '' : 'At least 3 characters');
      return;
    }
    setState(() => _checkingUsername = true);
    _debounce = Timer(const Duration(milliseconds: 600), () async {
      final available = await ApiService.checkUsername(v);
      if (!mounted) return;
      setState(() {
        _checkingUsername = false;
        _usernameAvailable = available;
        _usernameError = available ? '' : 'Username already taken';
      });
    });
  }

  void _onPasswordChanged(String value) {
    setState(() {
      _passwordError = (value.isNotEmpty && value.length < 12)
          ? 'Minimum 12 characters'
          : '';
    });
  }

  int? get _heightCm {
    final s = _heightController.text.trim();
    if (s.isEmpty) return null;
    return int.tryParse(s);
  }

  bool get _allValid {
    if (!_usernameAvailable) return false;
    if (_usernameController.text.trim().isEmpty) return false;
    if (_passwordController.text.length < 12) return false;
    if (_dob == null) return false;
    if (_sex == null) return false;
    if (_sexuality == null) return false;
    if (_starSign == null) return false;
    final h = _heightCm;
    if (h == null || h < 100 || h > 250) return false;
    if (_headlineController.text.trim().isEmpty) return false;
    if (_headlineController.text.trim().length > 50) return false;
    if (_bioController.text.trim().isEmpty) return false;
    if (_bioController.text.trim().length > 150) return false;
    return true;
  }

  String _dobIso(DateTime d) =>
      '${d.year.toString().padLeft(4, '0')}-${d.month.toString().padLeft(2, '0')}-${d.day.toString().padLeft(2, '0')}';

  Future<void> _submit() async {
    if (!_allValid) return;
    setState(() {
      _submitting = true;
      _generalError = '';
    });

    final username = _usernameController.text.trim();
    final password = _passwordController.text;

    final result = await ApiService.register(
      username,
      password,
      age: _age,
      sex: _sex,
      dateOfBirth: _dobIso(_dob!),
      sexuality: _sexuality,
      starSign: _starSign,
      height: _heightCm,
      headline: _headlineController.text.trim(),
      bio: _bioController.text.trim(),
    );

    if (result['success'] == true) {
      final token = await AuthService().login(username, password);
      if (token != null) {
        final prefs = await SharedPreferences.getInstance();
        await prefs.setString('username', username);
        if (mounted) {
          Navigator.of(context).pushAndRemoveUntil(
            MaterialPageRoute(builder: (_) => const MainScreen()),
            (route) => false,
          );
        }
        return;
      }
      if (mounted) {
        setState(() {
          _submitting = false;
          _generalError = 'Account created but login failed.';
        });
      }
    } else {
      if (mounted) {
        setState(() {
          _submitting = false;
          _generalError = (result['message'] as String?) ??
              'Registration failed. Please try again.';
        });
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: _bg,
      appBar: AppBar(
        backgroundColor: _bg,
        title: const Text('Create Account'),
        leading: const BackButton(color: Colors.white),
      ),
      body: SafeArea(
        child: SingleChildScrollView(
          padding: const EdgeInsets.fromLTRB(24, 20, 24, 32),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              _sectionLabel('Account'),
              const SizedBox(height: 8),
              _usernameField(),
              const SizedBox(height: 16),
              _passwordField(),
              const SizedBox(height: 24),

              _sectionLabel('About you'),
              const SizedBox(height: 8),
              _dobPicker(),
              const SizedBox(height: 16),
              _dropdown(
                label: 'Sex',
                value: _sex,
                options: _sexOptions,
                onChanged: (v) => setState(() => _sex = v),
              ),
              const SizedBox(height: 16),
              _dropdown(
                label: 'Sexuality',
                value: _sexuality,
                options: _sexualities,
                onChanged: (v) => setState(() => _sexuality = v),
              ),
              const SizedBox(height: 16),
              _dropdown(
                label: 'Star Sign',
                value: _starSign,
                options: _starSigns,
                onChanged: (v) => setState(() => _starSign = v),
              ),
              const SizedBox(height: 16),
              _heightField(),
              const SizedBox(height: 24),

              _sectionLabel('Profile text'),
              const SizedBox(height: 8),
              _headlineField(),
              const SizedBox(height: 16),
              _bioField(),
              const SizedBox(height: 24),

              if (_generalError.isNotEmpty) ...[
                Text(_generalError,
                    style: const TextStyle(color: Colors.redAccent)),
                const SizedBox(height: 12),
              ],

              SizedBox(
                width: double.infinity,
                height: 52,
                child: ElevatedButton(
                  onPressed:
                      (_allValid && !_submitting) ? _submit : null,
                  style: ElevatedButton.styleFrom(
                    backgroundColor: const Color(0xFFFFC107),
                    foregroundColor: Colors.black,
                    disabledBackgroundColor:
                        const Color(0xFFFFC107).withOpacity(0.35),
                    disabledForegroundColor: Colors.black54,
                    shape: RoundedRectangleBorder(
                      borderRadius: BorderRadius.circular(10),
                    ),
                  ),
                  child: _submitting
                      ? const SizedBox(
                          height: 22,
                          width: 22,
                          child: CircularProgressIndicator(
                              color: Colors.black, strokeWidth: 2.5),
                        )
                      : const Text('CREATE ACCOUNT',
                          style: TextStyle(
                              fontSize: 15, fontWeight: FontWeight.bold)),
                ),
              ),
              const SizedBox(height: 8),
            ],
          ),
        ),
      ),
    );
  }

  // ── Field builders ─────────────────────────────────────────────────────────

  Widget _sectionLabel(String text) => Text(
        text.toUpperCase(),
        style: const TextStyle(
          color: Colors.white54,
          fontSize: 11,
          fontWeight: FontWeight.w700,
          letterSpacing: 1.2,
        ),
      );

  Widget _usernameField() => TextField(
        controller: _usernameController,
        onChanged: _onUsernameChanged,
        style: const TextStyle(color: Colors.white),
        decoration: InputDecoration(
          labelText: 'Username',
          filled: true,
          fillColor: _fieldFill,
          border: OutlineInputBorder(
            borderRadius: BorderRadius.circular(10),
            borderSide: BorderSide.none,
          ),
          prefixIcon: const Icon(Icons.person_outline),
          suffixIcon: _checkingUsername
              ? const Padding(
                  padding: EdgeInsets.all(12),
                  child: SizedBox(
                    width: 18,
                    height: 18,
                    child: CircularProgressIndicator(
                        strokeWidth: 2, color: Colors.blueAccent),
                  ),
                )
              : _usernameController.text.trim().length >= 3
                  ? Icon(
                      _usernameAvailable
                          ? Icons.check_circle
                          : Icons.cancel,
                      color: _usernameAvailable
                          ? Colors.greenAccent
                          : Colors.redAccent,
                    )
                  : null,
          errorText: _usernameError.isEmpty ? null : _usernameError,
        ),
      );

  Widget _passwordField() => TextField(
        controller: _passwordController,
        obscureText: true,
        onChanged: _onPasswordChanged,
        style: const TextStyle(color: Colors.white),
        decoration: InputDecoration(
          labelText: 'Password',
          filled: true,
          fillColor: _fieldFill,
          border: OutlineInputBorder(
            borderRadius: BorderRadius.circular(10),
            borderSide: BorderSide.none,
          ),
          prefixIcon: const Icon(Icons.lock_outline),
          helperText: 'Minimum 12 characters',
          helperStyle: const TextStyle(color: Colors.grey),
          errorText: _passwordError.isEmpty ? null : _passwordError,
        ),
      );

  Widget _dobPicker() {
    final dobStr = _dob == null
        ? 'Select date of birth (18+)'
        : '${_dob!.day.toString().padLeft(2, '0')}/${_dob!.month.toString().padLeft(2, '0')}/${_dob!.year}  ·  age $_age';
    return Container(
      decoration: BoxDecoration(
        color: _fieldFill,
        borderRadius: BorderRadius.circular(10),
      ),
      padding: const EdgeInsets.all(8),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          Padding(
            padding: const EdgeInsets.fromLTRB(8, 6, 8, 8),
            child: Text(
              dobStr,
              style: TextStyle(
                color: _dob == null ? Colors.white54 : Colors.white,
                fontSize: 14,
                fontWeight:
                    _dob == null ? FontWeight.normal : FontWeight.w600,
              ),
            ),
          ),
          DatePicker(
            minDate: _minDob,
            maxDate: _maxDob,
            initialDate: DateTime(_maxDob.year - 2, 6, 15),
            selectedDate: _dob,
            onDateSelected: (d) => setState(() => _dob = d),
            currentDateDecoration: BoxDecoration(
              border: Border.all(color: Colors.blueAccent),
              shape: BoxShape.circle,
            ),
            selectedCellDecoration: const BoxDecoration(
              color: Colors.blueAccent,
              shape: BoxShape.circle,
            ),
            enabledCellsTextStyle:
                const TextStyle(color: Colors.white70),
            disabledCellsTextStyle:
                const TextStyle(color: Color(0xFF3A3A5E)),
            selectedCellTextStyle: const TextStyle(
                color: Colors.white, fontWeight: FontWeight.bold),
            currentDateTextStyle:
                const TextStyle(color: Colors.blueAccent),
            leadingDateTextStyle: const TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.bold,
                fontSize: 15),
            slidersColor: Colors.blueAccent,
            slidersSize: 18,
            splashColor: Colors.blueAccent.withOpacity(0.2),
            highlightColor: Colors.blueAccent.withOpacity(0.1),
          ),
        ],
      ),
    );
  }

  Widget _dropdown({
    required String label,
    required String? value,
    required List<String> options,
    required ValueChanged<String?> onChanged,
  }) =>
      DropdownButtonFormField<String?>(
        value: value,
        dropdownColor: _fieldFill,
        style: const TextStyle(color: Colors.white),
        decoration: InputDecoration(
          labelText: label,
          filled: true,
          fillColor: _fieldFill,
          border: OutlineInputBorder(
            borderRadius: BorderRadius.circular(10),
            borderSide: BorderSide.none,
          ),
        ),
        items: options
            .map((o) => DropdownMenuItem<String?>(value: o, child: Text(o)))
            .toList(),
        onChanged: onChanged,
      );

  Widget _heightField() => TextField(
        controller: _heightController,
        keyboardType: TextInputType.number,
        onChanged: (_) => setState(() {}),
        style: const TextStyle(color: Colors.white),
        decoration: InputDecoration(
          labelText: 'Height (cm, 100–250)',
          filled: true,
          fillColor: _fieldFill,
          border: OutlineInputBorder(
            borderRadius: BorderRadius.circular(10),
            borderSide: BorderSide.none,
          ),
          prefixIcon: const Icon(Icons.straighten),
        ),
      );

  Widget _headlineField() => TextField(
        controller: _headlineController,
        maxLength: 50,
        onChanged: (_) => setState(() {}),
        style: const TextStyle(color: Colors.white),
        decoration: InputDecoration(
          labelText: 'Headline',
          hintText: 'A short one-liner about you',
          hintStyle: const TextStyle(color: Colors.white38),
          filled: true,
          fillColor: _fieldFill,
          border: OutlineInputBorder(
            borderRadius: BorderRadius.circular(10),
            borderSide: BorderSide.none,
          ),
          counterStyle: const TextStyle(color: Colors.white38),
        ),
      );

  Widget _bioField() => TextField(
        controller: _bioController,
        maxLines: 3,
        maxLength: 150,
        onChanged: (_) => setState(() {}),
        style: const TextStyle(color: Colors.white),
        decoration: InputDecoration(
          labelText: 'Bio',
          hintText: 'A few sentences about yourself',
          hintStyle: const TextStyle(color: Colors.white38),
          filled: true,
          fillColor: _fieldFill,
          border: OutlineInputBorder(
            borderRadius: BorderRadius.circular(10),
            borderSide: BorderSide.none,
          ),
          counterStyle: const TextStyle(color: Colors.white38),
        ),
      );
}

