Future<void> _saveFilterPreference(_RankFilter filter) async {
  final prefs = await SharedPreferences.getInstance();
  await prefs.setString('wlm_rank_filter', filter.toStorageKey());
}

List<_WhoLikesMeEntry> get _filteredEntries {
  List<_WhoLikesMeEntry> result;
  switch (_rankFilter) {
    case _RankFilter.onlyOne:
      // Show only users who have YOU at rank #1
      result = _entries.where((e) => e.hasIncomingLock).toList();
      break;
    case _RankFilter.topThree:
      // Show users who ranked YOU at 1, 2, or 3
      result = _entries.where((e) {
        final rank = e.theirRankOfMe;
        return rank != null && rank >= 1 && rank <= 3;
      }).toList();
      break;
    case _RankFilter.all:
      result = _entries;
      break;
  }
  debugPrint('[WhoLikesMe] Filter=$_rankFilter, Total=${_entries.length}, Filtered=${result.length}');
  return result;
}

Future<String?> _getToken() async {
  final prefs = await SharedPreferences.getInstance();
  return prefs.getString('jwt_token');

