Future<void> _blockUser(int userId) async {
  // Optimistic: remove from list + mark blocked. Revert on failure.
  final removed = _users.where((u) => u.id == userId).toList();
  setState(() {
    _blockedIds.add(userId);
    _users.removeWhere((u) => u.id == userId);
  });
  try {
    final resp = await http.post(
      Uri.parse('$_baseUrl/api/block'),
      headers: {
        'Content-Type': 'application/json',
        if (_token != null) 'Authorization': 'Bearer $_token',
      },
      body: jsonEncode({'blocked_user_id': userId}),
    );
    if (resp.statusCode != 200 && resp.statusCode != 201) {
      // Roll back
      setState(() {
        _blockedIds.remove(userId);
        _users.addAll(removed);
      });
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('Block failed (${resp.statusCode})')),
