import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import '../core/config.dart';
import '../services/api_service.dart';
import '../widgets/authed_image.dart';

class BlockedUsersScreen extends StatefulWidget {
  const BlockedUsersScreen({super.key});

  @override
  State<BlockedUsersScreen> createState() => _BlockedUsersScreenState();
}

class _BlockedUsersScreenState extends State<BlockedUsersScreen> {
  static String get _baseUrl => BaseConfig.baseUrl;

  bool _loading = true;
  String? _error;
  List<Map<String, dynamic>> _blocked = [];

  @override
  void initState() {
    super.initState();
    _load();
  }

  Future<void> _load() async {
    setState(() {
      _loading = true;
      _error = null;
    });
    try {
      final token = await ApiService.getToken();
      final resp = await http.get(
        Uri.parse('$_baseUrl/api/blocked'),
        headers: {
          'Content-Type': 'application/json',
          if (token != null) 'Authorization': 'Bearer $token',
        },
      );
      if (resp.statusCode == 200) {
        final data = jsonDecode(resp.body) as Map<String, dynamic>;
        final items = (data['users'] as List<dynamic>? ?? [])
            .cast<Map<String, dynamic>>();
        // Most recent first. Fallback to list order if no timestamp.
        items.sort((a, b) {
          final ta = a['blocked_at']?.toString() ?? '';
          final tb = b['blocked_at']?.toString() ?? '';
          return tb.compareTo(ta);
        });
        if (!mounted) return;
        setState(() {
          _blocked = items;
          _loading = false;
        });
      } else {
        if (!mounted) return;
        setState(() {
          _error = 'Failed to load (${resp.statusCode})';
          _loading = false;
        });
      }
    } catch (e) {
      if (!mounted) return;
      setState(() {
        _error = 'Connection error';
        _loading = false;
      });
    }
  }

  Future<void> _confirmUnblock(Map<String, dynamic> entry) async {
    final username = entry['username']?.toString() ?? 'this user';
    final confirmed = await showDialog<bool>(
      context: context,
      builder: (ctx) => AlertDialog(
        backgroundColor: const Color(0xFF1A1A1A),
        title: const Text('Unblock user?',
            style: TextStyle(color: Colors.white)),
        content: Text(
          'Are you sure you want to unblock $username?',
          style: const TextStyle(color: Colors.white70),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.of(ctx).pop(false),
            child: const Text('No'),
          ),
          TextButton(
            onPressed: () => Navigator.of(ctx).pop(true),
            style: TextButton.styleFrom(foregroundColor: Colors.redAccent),
            child: const Text('Unblock'),
          ),
        ],
      ),
    );
    if (confirmed == true) {
      await _unblock(entry);
    }
  }

  Future<void> _unblock(Map<String, dynamic> entry) async {
    final userId = entry['id'];
    if (userId == null) return;
    try {
      final token = await ApiService.getToken();
      final resp = await http.delete(
        Uri.parse('$_baseUrl/api/block/$userId'),
        headers: {
          'Content-Type': 'application/json',
          if (token != null) 'Authorization': 'Bearer $token',
        },
      );
      if (resp.statusCode == 200 || resp.statusCode == 204) {
        setState(() => _blocked.removeWhere((e) => e['id'] == userId));
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(content: Text('Unblocked ${entry['username']}')),
          );
        }
      } else if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('Unblock failed (${resp.statusCode})')),
        );
      }
    } catch (_) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Connection error')),
        );
      }
    }
  }

  String _relTime(String? iso) {
    if (iso == null || iso.isEmpty) return '';
    DateTime? t;
    try {
      final parsed = DateTime.parse(iso);
      t = parsed.isUtc ? parsed : DateTime.parse('${iso}Z');
    } catch (_) {
      return '';
    }
    final now = DateTime.now().toUtc();
    final d = now.difference(t);
    if (d.inSeconds < 60) return 'just now';
    if (d.inMinutes < 60) return '${d.inMinutes}m ago';
    if (d.inHours < 24) return '${d.inHours}h ago';
    if (d.inDays < 7) return '${d.inDays}d ago';
    if (d.inDays < 30) return '${d.inDays ~/ 7}w ago';
    if (d.inDays < 365) return '${d.inDays ~/ 30}mo ago';
    return '${d.inDays ~/ 365}y ago';
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: const Color(0xFF0E0E0E),
      appBar: AppBar(
        backgroundColor: const Color(0xFF0E0E0E),
        title: const Text('Blocked Users'),
        actions: [
          IconButton(
            icon: const Icon(Icons.refresh, color: Colors.white54),
            onPressed: _load,
          ),
        ],
      ),
      body: _buildBody(),
    );
  }

  Widget _buildBody() {
    if (_loading) {
      return const Center(
        child: CircularProgressIndicator(color: Color(0xFFFFC107)),
      );
    }
    if (_error != null) {
      return Center(
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            Text(_error!, style: const TextStyle(color: Colors.redAccent)),
            const SizedBox(height: 12),
            TextButton(onPressed: _load, child: const Text('Retry')),
          ],
        ),
      );
    }
    if (_blocked.isEmpty) {
      return const Center(
        child: Padding(
          padding: EdgeInsets.all(32),
          child: Text(
            "You haven't blocked anyone.",
            style: TextStyle(color: Colors.white54, fontSize: 14),
            textAlign: TextAlign.center,
          ),
        ),
      );
    }
    return RefreshIndicator(
      onRefresh: _load,
      color: const Color(0xFFFFC107),
      child: ListView.separated(
        padding: const EdgeInsets.symmetric(vertical: 8),
        itemCount: _blocked.length,
        separatorBuilder: (_, __) =>
            const Divider(height: 1, color: Colors.white10),
        itemBuilder: (context, index) {
          final entry = _blocked[index];
          final username = entry['username']?.toString() ?? '';
          final id = entry['id'];
          final photoUrl = id == null
              ? null
              : '$_baseUrl/api/users/$id/photo';
          return ListTile(
            contentPadding:
                const EdgeInsets.symmetric(horizontal: 16, vertical: 4),
            leading: CircleAvatar(
              radius: 22,
              backgroundColor: Colors.white12,
              child: ClipOval(
                child: photoUrl == null
                    ? Text(
                        username.isNotEmpty
                            ? username[0].toUpperCase()
                            : '?',
                        style: const TextStyle(
                            color: Colors.white,
                            fontWeight: FontWeight.bold),
                      )
                    : AuthedImage(
                        url: photoUrl,
                        width: 44,
                        height: 44,
                        fit: BoxFit.cover,
                        errorBuilder: (_) => Text(
                          username.isNotEmpty
                              ? username[0].toUpperCase()
                              : '?',
                          style: const TextStyle(
                              color: Colors.white,
                              fontWeight: FontWeight.bold),
                        ),
                      ),
              ),
            ),
            title: Text(
              username,
              style: const TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.w600,
              ),
            ),
            subtitle: Text(
              _relTime(entry['blocked_at']?.toString()),
              style: const TextStyle(color: Colors.white38, fontSize: 12),
            ),
            trailing: IconButton(
              icon: const Icon(Icons.close, color: Colors.redAccent),
              tooltip: 'Unblock',
              onPressed: () => _confirmUnblock(entry),
            ),
          );
        },
      ),
    );
  }
}

