import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';

/// App-wide preference for which photo type to show across Discover, WIL,
/// WLM, and Matches. Persisted to SharedPreferences.
enum PhotoType { face, body }

class PhotoTypeStore {
  static const _prefKey = 'photo_type_preference';

  /// Shared notifier. main_screen creates and owns one; all tab screens
  /// subscribe to it.
  static ValueNotifier<PhotoType> create() =>
      ValueNotifier<PhotoType>(PhotoType.face);

  static Future<void> load(ValueNotifier<PhotoType> notifier) async {
    final prefs = await SharedPreferences.getInstance();
    final raw = prefs.getString(_prefKey);
    if (raw == 'body') notifier.value = PhotoType.body;
    if (raw == 'face') notifier.value = PhotoType.face;
  }

  static Future<void> save(PhotoType t) async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString(_prefKey, t == PhotoType.body ? 'body' : 'face');
  }
}

