Future<void> _unlikeUser(int userId) async {
  // Remove from list immediately to prevent shrink animation
  setState(() => _likes.removeWhere((like) => (like['id'] as int?) == userId));

  final token = await _getToken();
  if (token == null) return;
  try {
    await http.delete(
      Uri.parse('$_baseUrl/api/like/$userId'),
      headers: {'Authorization': 'Bearer $token'},
    );
    if (mounted) {
      ScaffoldMessenger.of(context)
          .showSnackBar(const SnackBar(content: Text('Removed from likes')));
    }
  } catch (e) {
    debugPrint('[WhoILike] unlike error: $e');
  }
}

