import 'package:flutter/material.dart';
import 'package:curved_navigation_bar/curved_navigation_bar.dart';
import '../core/photo_type.dart';
import 'users_screen.dart';
import 'who_i_like_screen.dart';
import 'who_likes_me_screen.dart';
import 'matches_screen.dart';

class MainScreen extends StatefulWidget {
  const MainScreen({super.key});

  @override
  State<MainScreen> createState() => _MainScreenState();
}

class _MainScreenState extends State<MainScreen> {
  int _currentIndex = 0;
  final List<bool> _initialized = [true, false, false, false];

  // Shared notifier so UsersScreen can signal WhoILikeScreen to refresh
  // immediately after a like is ranked, without waiting for the 10s timer.
  final ValueNotifier<int> _wilRefreshTick = ValueNotifier<int>(0);

  // Notifier to trigger refresh of UsersScreen when Discover tab is tapped
  final ValueNotifier<int> _usersRefreshTick = ValueNotifier<int>(0);

  // Notifier so any like-flow caller can trigger a Matches reload
  // when a mutual match is created.
  final ValueNotifier<int> _matchesRefreshTick = ValueNotifier<int>(0);

  // Global photo-type preference: face | body. Shared across all 4 tabs.
  final ValueNotifier<PhotoType> _photoType = PhotoTypeStore.create();

  static const _navBackground = Color(0xFF1E1E2E);

  @override
  void initState() {
    super.initState();
    PhotoTypeStore.load(_photoType);
    _photoType.addListener(_persistPhotoType);
  }

  void _persistPhotoType() {
    PhotoTypeStore.save(_photoType.value);
  }

  @override
  void dispose() {
    _photoType.removeListener(_persistPhotoType);
    _photoType.dispose();
    _wilRefreshTick.dispose();
    _usersRefreshTick.dispose();
    _matchesRefreshTick.dispose();
    super.dispose();
  }

  void _switchTab(int index) {
    setState(() {
      _initialized[index] = true;
      _currentIndex = index;
    });
  }

  final List<Widget> _navItems = const [
    Icon(Icons.explore,        color: Colors.white, size: 26), // 0 Search
    Icon(Icons.arrow_forward,  color: Colors.white, size: 26), // 1 Who I Like
    Icon(Icons.arrow_back,     color: Colors.white, size: 26), // 2 Who Likes Me
    Icon(Icons.favorite,       color: Colors.white, size: 26), // 3 Matches
  ];

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      extendBody: true,
      body: IndexedStack(
        index: _currentIndex,
        children: [
          UsersScreen(
            wilRefreshTick: _wilRefreshTick,
            refreshTick: _usersRefreshTick,
            matchesRefreshTick: _matchesRefreshTick,
            onSwitchTab: _switchTab,
            photoType: _photoType,
          ),
          _initialized[1]
              ? WhoILikeScreen(
                  onSwitchTab: _switchTab,
                  refreshTick: _wilRefreshTick,
                  photoType: _photoType,
                )
              : const SizedBox.shrink(),
          _initialized[2]
              ? WhoLikesMeScreen(
                  onSwitchTab: _switchTab,
                  wilRefreshTick: _wilRefreshTick,
                  matchesRefreshTick: _matchesRefreshTick,
                  photoType: _photoType,
                )
              : const SizedBox.shrink(),
          _initialized[3]
              ? MatchesScreen(
                  refreshTick: _matchesRefreshTick,
                  photoType: _photoType,
                )
              : const SizedBox.shrink(),
        ],
      ),
      bottomNavigationBar: CurvedNavigationBar(
        index: _currentIndex,
        height: 60,
        color: _navBackground,
        backgroundColor: Colors.transparent,
        buttonBackgroundColor: Colors.blueAccent,
        animationDuration: const Duration(milliseconds: 300),
        animationCurve: Curves.easeInOut,
        items: _navItems,
        onTap: (index) {
          // Always refetch Discover on ANY tap of tab 0 (including repeat taps).
          if (index == 0) {
            _usersRefreshTick.value = _usersRefreshTick.value + 1;
          }

          setState(() {
            _initialized[index] = true;
            _currentIndex = index;
          });
        },
      ),
    );
  }
}

