import '../core/config.dart';
import 'dart:async';
import 'dart:convert';
import 'package:http/http.dart' as http;
import 'package:shared_preferences/shared_preferences.dart';

class ApiService {
  static String get baseUrl => BaseConfig.baseUrl;

  // Check username availability
  static Future<bool> checkUsername(String username) async {
    try {
      final response = await http.get(
        Uri.parse('$baseUrl/api/check-username?username=${Uri.encodeComponent(username)}'),
      );
      if (response.statusCode == 200) {
        return jsonDecode(response.body)['available'] == true;
      }
      return false;
    } catch (e) {
      return false;
    }
  }

  // Register user.
  // Returns {success: bool, kind?: String, message?: String}.
  // kind ∈ {duplicate, validation, timeout, network, server} when success=false.
  static Future<Map<String, dynamic>> register(
    String username,
    String password, {
    int? age,
    String? sex,
    String? dateOfBirth, // ISO 'YYYY-MM-DD'
    String? sexuality,
    String? starSign,
    int? height,
    String? headline,
    String? bio,
  }) async {
    try {
      final response = await http
          .post(
            Uri.parse('$baseUrl/api/register'),
            headers: {'Content-Type': 'application/json'},
            body: jsonEncode({
              'username': username,
              'email': '$username@logindemo.com',
              'password': password,
              if (age != null) 'age': age,
              if (sex != null) 'sex': sex,
              if (dateOfBirth != null) 'date_of_birth': dateOfBirth,
              if (sexuality != null) 'sexuality': sexuality,
              if (starSign != null) 'star_sign': starSign,
              if (height != null) 'height': height,
              if (headline != null) 'headline': headline,
              if (bio != null) 'bio': bio,
            }),
          )
          .timeout(const Duration(seconds: 15));

      if (response.statusCode == 201) {
        return {'success': true};
      }

      dynamic detail;
      try {
        final body = jsonDecode(response.body);
        if (body is Map) detail = body['detail'];
      } catch (_) {}

      switch (response.statusCode) {
        case 409:
          return {
            'success': false,
            'kind': 'duplicate',
            'message': detail is String ? detail : 'Username already taken',
          };
        case 422:
          String msg = 'Missing required fields';
          if (detail is List && detail.isNotEmpty) {
            final first = detail.first;
            if (first is Map) {
              final loc = first['loc'];
              final field = (loc is List && loc.length >= 2) ? loc[1] : null;
              msg = field != null
                  ? 'Missing or invalid field: $field'
                  : (first['msg']?.toString() ?? msg);
            }
          } else if (detail is String) {
            msg = detail;
          }
          return {'success': false, 'kind': 'validation', 'message': msg};
        default:
          return {
            'success': false,
            'kind': 'server',
            'message': detail is String
                ? detail
                : 'Registration failed. Please try again.',
          };
      }
    } on TimeoutException {
      return {
        'success': false,
        'kind': 'timeout',
        'message': 'Connection problem, try again',
      };
    } catch (_) {
      return {
        'success': false,
        'kind': 'network',
        'message': 'Connection problem, try again',
      };
    }
  }

  // Login user
  static Future<Map<String, dynamic>> login(String username, String password) async {
    try {
      final response = await http.post(
        Uri.parse('$baseUrl/api/login'),
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: 'username=${Uri.encodeComponent(username)}&password=${Uri.encodeComponent(password)}',
      );

      final responseData = jsonDecode(response.body);

      if (response.statusCode == 200 && responseData['access_token'] != null) {
        // Store JWT token
        await _storeToken(responseData['access_token']);
      }

      return {
        'success': response.statusCode == 200,
        'data': responseData,
        'statusCode': response.statusCode,
      };
    } catch (e) {
      return {
        'success': false,
        'error': e.toString(),
      };
    }
  }

  // Get current user profile
  static Future<Map<String, dynamic>> getProfile() async {
    try {
      final token = await _getToken();
      final response = await http.get(
        Uri.parse('$baseUrl/api/users/me'),
        headers: {
          'Content-Type': 'application/json',
          if (token != null) 'Authorization': 'Bearer $token',
        },
      );
      return {
        'success': response.statusCode == 200,
        'data': jsonDecode(response.body),
        'statusCode': response.statusCode,
      };
    } catch (e) {
      return {
        'success': false,
        'error': e.toString(),
      };
    }
  }

  // Get the token for use in image URLs
  static Future<String?> getToken() async => await _getToken();

  // Get hello world data
  static Future<Map<String, dynamic>> getHello() async {
    try {
      final token = await _getToken();

      final response = await http.get(
        Uri.parse('$baseUrl/api/hello'),
        headers: {
          'Content-Type': 'application/json',
          if (token != null) 'Authorization': 'Bearer $token',
        },
      );

      return {
        'success': response.statusCode == 200,
        'data': jsonDecode(response.body),
        'statusCode': response.statusCode,
      };
    } catch (e) {
      return {
        'success': false,
        'error': e.toString(),
      };
    }
  }

  // Store JWT token
  static Future<void> _storeToken(String token) async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('jwt_token', token);
  }

  // Get stored JWT token
  static Future<String?> _getToken() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getString('jwt_token');
  }

  // Check if user is logged in
  static Future<bool> isLoggedIn() async {
    final token = await _getToken();
    return token != null && token.isNotEmpty;
  }

  // Logout user
  static Future<void> logout() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.remove('jwt_token');
  }
}

