import 'dart:async';
import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';
import '../services/api_service.dart';
import '../services/auth_service.dart';
import 'main_screen.dart';

/// Inserted between RegistrationScreen (form fill) and auto-login.
/// Collects an optional referrer username, then issues the register call
/// with `referred_by` populated (or null after a confirm dialog).
class ReferrerCodeScreen extends StatefulWidget {
  // Registration payload handed down from RegistrationScreen.
  final String username;
  final String password;
  final int age;
  final String sex;
  final String dateOfBirth; // ISO YYYY-MM-DD
  final String sexuality;
  final String starSign;
  final int height;
  final String headline;
  final String bio;

  const ReferrerCodeScreen({
    super.key,
    required this.username,
    required this.password,
    required this.age,
    required this.sex,
    required this.dateOfBirth,
    required this.sexuality,
    required this.starSign,
    required this.height,
    required this.headline,
    required this.bio,
  });

  @override
  State<ReferrerCodeScreen> createState() => _ReferrerCodeScreenState();
}

class _ReferrerCodeScreenState extends State<ReferrerCodeScreen> {
  static const _bg = Color(0xFF0E0E0E);
  static const _fieldFill = Color(0xFF2A2A2A);

  final _controller = TextEditingController();
  Timer? _debounce;
  bool _checking = false;
  bool? _exists; // null = not checked, true = exists, false = not found
  String _inlineError = ''; // e.g. self-referral
  String _generalError = '';
  bool _submitting = false;

  @override
  void dispose() {
    _debounce?.cancel();
    _controller.dispose();
    super.dispose();
  }

  String get _normalized => _controller.text.trim().toLowerCase();

  bool get _isSelfReferral =>
      _normalized.isNotEmpty && _normalized == widget.username.toLowerCase();

  void _onChanged(String _) {
    _debounce?.cancel();
    setState(() {
      _exists = null;
      _checking = false;
      _inlineError = '';
    });
    final v = _normalized;
    if (v.isEmpty) return;
    if (_isSelfReferral) {
      setState(() => _inlineError = "You can't refer yourself");
      return;
    }
    setState(() => _checking = true);
    _debounce = Timer(const Duration(milliseconds: 600), () async {
      final exists = await ApiService.checkUsernameExists(v);
      if (!mounted) return;
      setState(() {
        _checking = false;
        _exists = exists;
      });
    });
  }

  Future<void> _onContinue() async {
    if (_submitting) return;
    final v = _normalized;

    // Case 1: empty field.
    if (v.isEmpty) {
      final proceed = await _confirm(
        title: 'Continue without referrer?',
        body: 'You can add a referrer later if you wish.',
        confirmLabel: 'Yes',
        cancelLabel: 'Go back',
      );
      if (proceed == true) await _finishRegister(referredBy: null);
      return;
    }

    // Case 2: self-referral (double check even though button is disabled).
    if (_isSelfReferral) {
      setState(() => _inlineError = "You can't refer yourself");
      return;
    }

    // Case 3: valid existing referrer.
    if (_exists == true) {
      await _finishRegister(referredBy: v);
      return;
    }

    // Case 4: typed but not found (or not yet checked — run a final check).
    if (_exists == null && !_checking) {
      setState(() => _checking = true);
      final exists = await ApiService.checkUsernameExists(v);
      if (!mounted) return;
      setState(() {
        _checking = false;
        _exists = exists;
      });
      if (exists) {
        await _finishRegister(referredBy: v);
        return;
      }
    }

    // Case 5: not found.
    if (_exists == false) {
      final proceed = await _confirm(
        title: 'Referrer not found',
        body:
            '“${_controller.text.trim()}” isn\'t a user on Datetris.\nContinue without a referrer?',
        confirmLabel: 'Yes',
        cancelLabel: 'Change code',
      );
      if (proceed == true) await _finishRegister(referredBy: null);
    }
  }

  Future<bool?> _confirm({
    required String title,
    required String body,
    required String confirmLabel,
    required String cancelLabel,
  }) {
    return showDialog<bool>(
      context: context,
      builder: (ctx) => AlertDialog(
        backgroundColor: const Color(0xFF1A1A1A),
        title: Text(title, style: const TextStyle(color: Colors.white)),
        content:
            Text(body, style: const TextStyle(color: Colors.white70)),
        actions: [
          TextButton(
            onPressed: () => Navigator.of(ctx).pop(false),
            child: Text(cancelLabel),
          ),
          TextButton(
            onPressed: () => Navigator.of(ctx).pop(true),
            style: TextButton.styleFrom(foregroundColor: const Color(0xFFFFC107)),
            child: Text(confirmLabel),
          ),
        ],
      ),
    );
  }

  Future<void> _finishRegister({required String? referredBy}) async {
    setState(() {
      _submitting = true;
      _generalError = '';
    });

    final result = await ApiService.register(
      widget.username,
      widget.password,
      age: widget.age,
      sex: widget.sex,
      dateOfBirth: widget.dateOfBirth,
      sexuality: widget.sexuality,
      starSign: widget.starSign,
      height: widget.height,
      headline: widget.headline,
      bio: widget.bio,
      referredBy: referredBy,
    );

    if (result['success'] == true) {
      final token =
          await AuthService().login(widget.username, widget.password);
      if (token != null) {
        final prefs = await SharedPreferences.getInstance();
        await prefs.setString('username', widget.username);
        if (mounted) {
          Navigator.of(context).pushAndRemoveUntil(
            MaterialPageRoute(builder: (_) => const MainScreen()),
            (route) => false,
          );
        }
        return;
      }
      if (mounted) {
        setState(() {
          _submitting = false;
          _generalError = 'Account created but login failed.';
        });
      }
    } else {
      if (mounted) {
        setState(() {
          _submitting = false;
          _generalError = (result['message'] as String?) ??
              'Registration failed. Please try again.';
        });
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    final hasText = _controller.text.trim().isNotEmpty;
    final canSubmit = !_submitting &&
        (!hasText || // empty is allowed (triggers confirm dialog)
            (hasText && !_isSelfReferral && !_checking));

    Widget? suffix;
    if (_checking) {
      suffix = const Padding(
        padding: EdgeInsets.all(12),
        child: SizedBox(
          width: 18,
          height: 18,
          child: CircularProgressIndicator(
              strokeWidth: 2, color: Colors.blueAccent),
        ),
      );
    } else if (_isSelfReferral) {
      suffix = const Icon(Icons.cancel, color: Colors.redAccent);
    } else if (hasText && _exists == true) {
      suffix = const Icon(Icons.check_circle, color: Colors.greenAccent);
    } else if (hasText && _exists == false) {
      suffix = const Icon(Icons.cancel, color: Colors.redAccent);
    }

    return Scaffold(
      backgroundColor: _bg,
      appBar: AppBar(
        backgroundColor: _bg,
        title: const Text('Referrer code'),
        leading: const BackButton(color: Colors.white),
      ),
      body: SafeArea(
        child: Padding(
          padding: const EdgeInsets.fromLTRB(24, 24, 24, 32),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              const Text(
                'Do you have a referrer code?',
                style: TextStyle(
                  color: Colors.white,
                  fontSize: 22,
                  fontWeight: FontWeight.bold,
                ),
              ),
              const SizedBox(height: 8),
              const Text(
                'Enter the username of the person who referred you. '
                'Leave blank if you came here on your own.',
                style: TextStyle(color: Colors.white70, fontSize: 13),
              ),
              const SizedBox(height: 24),
              TextField(
                controller: _controller,
                autofocus: true,
                onChanged: _onChanged,
                style: const TextStyle(color: Colors.white),
                decoration: InputDecoration(
                  labelText: 'Referrer username',
                  filled: true,
                  fillColor: _fieldFill,
                  border: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(10),
                    borderSide: BorderSide.none,
                  ),
                  prefixIcon: const Icon(Icons.person_search_outlined),
                  suffixIcon: suffix,
                  errorText:
                      _inlineError.isEmpty ? null : _inlineError,
                ),
              ),
              const Spacer(),
              if (_generalError.isNotEmpty) ...[
                Text(_generalError,
                    style: const TextStyle(color: Colors.redAccent)),
                const SizedBox(height: 12),
              ],
              SizedBox(
                width: double.infinity,
                height: 52,
                child: ElevatedButton(
                  onPressed: canSubmit ? _onContinue : null,
                  style: ElevatedButton.styleFrom(
                    backgroundColor: const Color(0xFFFFC107),
                    foregroundColor: Colors.black,
                    disabledBackgroundColor:
                        const Color(0xFFFFC107).withOpacity(0.35),
                    shape: RoundedRectangleBorder(
                      borderRadius: BorderRadius.circular(10),
                    ),
                  ),
                  child: _submitting
                      ? const SizedBox(
                          width: 22,
                          height: 22,
                          child: CircularProgressIndicator(
                              color: Colors.black, strokeWidth: 2.5),
                        )
                      : const Text('CONTINUE',
                          style: TextStyle(
                              fontSize: 15, fontWeight: FontWeight.bold)),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

