      sex: widget.sex,
      dateOfBirth: widget.dateOfBirth,
      sexuality: widget.sexuality,
      starSign: widget.starSign,
      height: widget.height,
      headline: widget.headline,
      bio: widget.bio,
      referredBy: referredBy,
    );

    if (result['success'] == true) {
      final token =
          await AuthService().login(widget.username, widget.password);
      if (token != null) {
        final prefs = await SharedPreferences.getInstance();
        await prefs.setString('username', widget.username);
        if (mounted) {
          Navigator.of(context).pushAndRemoveUntil(
            MaterialPageRoute(builder: (_) => const MainScreen()),
            (route) => false,
          );
        }
        return;
      }
      if (mounted) {
        setState(() {
          _submitting = false;
          _generalError = 'Account created but login failed.';
        });
      }
    } else {
      if (mounted) {
        setState(() {
          _submitting = false;
          _generalError = (result['message'] as String?) ??
              'Registration failed. Please try again.';
        });
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    final hasText = _controller.text.trim().isNotEmpty;
    final canSubmit = !_submitting &&
        (!hasText || // empty is allowed (triggers confirm dialog)
            (hasText && !_isSelfReferral && !_checking));

    Widget? suffix;
    if (_checking) {
      suffix = const Padding(
        padding: EdgeInsets.all(12),
        child: SizedBox(
          width: 18,
          height: 18,
          child: CircularProgressIndicator(
              strokeWidth: 2, color: Colors.blueAccent),
        ),
      );
    } else if (_isSelfReferral) {
      suffix = const Icon(Icons.cancel, color: Colors.redAccent);
    } else if (hasText && _exists == true) {
      suffix = const Icon(Icons.check_circle, color: Colors.greenAccent);
    } else if (hasText && _exists == false) {
      suffix = const Icon(Icons.cancel, color: Colors.redAccent);
    }

    return Scaffold(
      backgroundColor: _bg,
      appBar: AppBar(
        backgroundColor: _bg,
        title: const Text('Referrer code'),
        leading: const BackButton(color: Colors.white),
      ),
      body: SafeArea(
        child: Padding(
          padding: const EdgeInsets.fromLTRB(24, 24, 24, 32),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              const Text(
                'Do you have a referrer code?',
                style: TextStyle(
                  color: Colors.white,
                  fontSize: 22,
                  fontWeight: FontWeight.bold,
                ),
              ),
              const SizedBox(height: 8),
              const Text(
                'Enter the username of the person who referred you. '
                'Leave blank if you came here on your own.',
                style: TextStyle(color: Colors.white70, fontSize: 13),
              ),
              const SizedBox(height: 24),
              TextField(
                controller: _controller,
                autofocus: true,
                onChanged: _onChanged,
                style: const TextStyle(color: Colors.white),
                decoration: InputDecoration(
                  labelText: 'Referrer username',
                  filled: true,
                  fillColor: _fieldFill,
                  border: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(10),
                    borderSide: BorderSide.none,
                  ),
                  prefixIcon: const Icon(Icons.person_search_outlined),
                  suffixIcon: suffix,
                  errorText:
                      _inlineError.isEmpty ? null : _inlineError,
                ),
              ),
              const Spacer(),
              if (_generalError.isNotEmpty) ...[
                Text(_generalError,
                    style: const TextStyle(color: Colors.redAccent)),
                const SizedBox(height: 12),
              ],
              SizedBox(
                width: double.infinity,
                height: 52,
                child: ElevatedButton(
                  onPressed: canSubmit ? _onContinue : null,
                  style: ElevatedButton.styleFrom(
                    backgroundColor: const Color(0xFFFFC107),
                    foregroundColor: Colors.black,
                    disabledBackgroundColor:
                        const Color(0xFFFFC107).withOpacity(0.35),
                    shape: RoundedRectangleBorder(
                      borderRadius: BorderRadius.circular(10),
                    ),
                  ),
                  child: _submitting
                      ? const SizedBox(
                          width: 22,
                          height: 22,
                          child: CircularProgressIndicator(
                              color: Colors.black, strokeWidth: 2.5),
                        )
                      : const Text('CONTINUE',
                          style: TextStyle(
                              fontSize: 15, fontWeight: FontWeight.bold)),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

