import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import '../services/api_service.dart';

class MyReferralsScreen extends StatefulWidget {
  const MyReferralsScreen({super.key});

  @override
  State<MyReferralsScreen> createState() => _MyReferralsScreenState();
}

class _MyReferralsScreenState extends State<MyReferralsScreen> {
  bool _loading = true;
  String? _error;
  String _code = '';
  num _totalValue = 0;
  List<Map<String, dynamic>> _events = [];

  @override
  void initState() {
    super.initState();
    _load();
  }

  Future<void> _load() async {
    setState(() {
      _loading = true;
      _error = null;
    });
    final res = await ApiService.fetchReferrals();
    if (!mounted) return;
    if (res['success'] == true) {
      final data = res['data'] as Map<String, dynamic>;
      final items = (data['events'] as List<dynamic>? ?? [])
          .cast<Map<String, dynamic>>();
      items.sort((a, b) {
        final ta = a['date']?.toString() ?? '';
        final tb = b['date']?.toString() ?? '';
        return tb.compareTo(ta);
      });
      setState(() {
        _code = (data['referral_code'] as String?) ?? '';
        _totalValue = (data['total_value'] as num?) ?? 0;
        _events = items;
        _loading = false;
      });
    } else {
      setState(() {
        _error = 'Failed to load (${res['statusCode'] ?? 'network'})';
        _loading = false;
      });
    }
  }

  void _copyCode() {
    Clipboard.setData(ClipboardData(text: _code));
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(content: Text('Copied "$_code" to clipboard')),
    );
  }

  String _relTime(String? iso) {
    if (iso == null || iso.isEmpty) return '';
    DateTime? t;
    try {
      final parsed = DateTime.parse(iso);
      t = parsed.isUtc ? parsed : DateTime.parse('${iso}Z');
    } catch (_) {
      return '';
    }
    final now = DateTime.now().toUtc();
    final d = now.difference(t);
    if (d.inSeconds < 60) return 'just now';
    if (d.inMinutes < 60) return '${d.inMinutes}m ago';
    if (d.inHours < 24) return '${d.inHours}h ago';
    if (d.inDays < 7) return '${d.inDays}d ago';
    if (d.inDays < 30) return '${d.inDays ~/ 7}w ago';
    if (d.inDays < 365) return '${d.inDays ~/ 30}mo ago';
    return '${d.inDays ~/ 365}y ago';
  }

  String _formatPoints(num v) {
    final i = v.toInt();
    return v == i ? '$i points' : '${v.toStringAsFixed(1)} points';
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: const Color(0xFF0E0E0E),
      appBar: AppBar(
        backgroundColor: const Color(0xFF0E0E0E),
        title: const Text('My Referrals'),
        actions: [
          IconButton(
            icon: const Icon(Icons.refresh, color: Colors.white54),
            onPressed: _load,
          ),
        ],
      ),
      body: _buildBody(),
    );
  }

  Widget _buildBody() {
    if (_loading) {
      return const Center(
        child: CircularProgressIndicator(color: Color(0xFFFFC107)),
      );
    }
    if (_error != null) {
      return Center(
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            Text(_error!, style: const TextStyle(color: Colors.redAccent)),
            const SizedBox(height: 12),
            TextButton(onPressed: _load, child: const Text('Retry')),
          ],
        ),
      );
    }
    return RefreshIndicator(
      onRefresh: _load,
      color: const Color(0xFFFFC107),
      child: ListView(
        padding: const EdgeInsets.fromLTRB(16, 16, 16, 32),
        children: [
          _codeCard(),
          const SizedBox(height: 12),
          _totalCard(),
          const SizedBox(height: 24),
          _sectionLabel('EVENTS'),
          const SizedBox(height: 8),
          if (_events.isEmpty)
            const Padding(
              padding: EdgeInsets.symmetric(vertical: 40),
              child: Center(
                child: Text(
                  "No referrals yet.\nShare your code to start earning.",
                  style: TextStyle(color: Colors.white54, fontSize: 14),
                  textAlign: TextAlign.center,
                ),
              ),
            )
          else
            ..._events.map(_eventRow),
        ],
      ),
    );
  }

  Widget _codeCard() {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 14),
      decoration: BoxDecoration(
        color: const Color(0xFF1A1A1A),
        borderRadius: BorderRadius.circular(12),
      ),
      child: Row(
        children: [
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                const Text('YOUR REFERRAL CODE',
                    style: TextStyle(
                        color: Colors.white54,
                        fontSize: 11,
                        fontWeight: FontWeight.w700,
                        letterSpacing: 1.2)),
                const SizedBox(height: 4),
                Text(
                  _code.isEmpty ? '—' : _code,
                  style: const TextStyle(
                    color: Colors.white,
                    fontSize: 20,
                    fontWeight: FontWeight.w600,
                  ),
                ),
              ],
            ),
          ),
          IconButton(
            icon: const Icon(Icons.copy, color: Color(0xFFFFC107)),
            tooltip: 'Copy',
            onPressed: _code.isEmpty ? null : _copyCode,
          ),
        ],
      ),
    );
  }

  Widget _totalCard() {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 14),
      decoration: BoxDecoration(
        color: const Color(0xFF1A1A1A),
        borderRadius: BorderRadius.circular(12),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          const Text('TOTAL EARNED',
              style: TextStyle(
                  color: Colors.white54,
                  fontSize: 11,
                  fontWeight: FontWeight.w700,
                  letterSpacing: 1.2)),
          const SizedBox(height: 4),
          Text(
            _formatPoints(_totalValue),
            style: const TextStyle(
              color: Color(0xFFFFC107),
              fontSize: 20,
              fontWeight: FontWeight.w700,
            ),
          ),
        ],
      ),
    );
  }

  Widget _sectionLabel(String text) => Text(
        text,
        style: const TextStyle(
          color: Colors.white54,
          fontSize: 11,
          fontWeight: FontWeight.w700,
          letterSpacing: 1.2,
        ),
      );

  Widget _eventRow(Map<String, dynamic> e) {
    final name = e['event_name']?.toString() ?? '';
    final value = (e['value'] as num?) ?? 0;
    final who = e['referred_username']?.toString() ?? '';
    final when = _relTime(e['date']?.toString());
    return Padding(
      padding: const EdgeInsets.only(bottom: 10),
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
        decoration: BoxDecoration(
          color: const Color(0xFF1A1A1A),
          borderRadius: BorderRadius.circular(10),
        ),
        child: Row(
          children: [
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(name,
                      style: const TextStyle(
                          color: Colors.white,
                          fontWeight: FontWeight.w600,
                          fontSize: 14)),
                  const SizedBox(height: 2),
                  Text(
                    who.isEmpty ? when : '$who · $when',
                    style: const TextStyle(
                        color: Colors.white54, fontSize: 12),
