import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import '../core/config.dart';
import 'api_service.dart';

/// Shared implementation of the "post a like" flow.
///
/// All three like entry points (Discover heart, Profile heart, WLM like-back)
/// share the same HTTP + optimistic-UI + navigation contract. This helper
/// owns:
///   - POST /api/like with Bearer token
///   - Accepting both 200 (matched) and 201 (liked) from the backend
///   - Showing the "🎉 It's a match!" snackbar on a match
///   - Rolling back optimistic UI + showing an error snackbar on failure
///
/// The caller supplies four callbacks so the helper doesn't have to know
/// about the caller's local state or its place in the navigation tree.
class LikeFlow {
  static Future<void> performLike({
    required BuildContext context,
    required int likedUserId,
    required VoidCallback onOptimistic,
    required VoidCallback onRollback,
    required VoidCallback onLikedNavigate,
    required VoidCallback onMatchedNavigate,
  }) async {
    onOptimistic();

    try {
      final token = await ApiService.getToken();
      final resp = await http.post(
        Uri.parse('${BaseConfig.baseUrl}/api/like'),
        headers: {
          'Content-Type': 'application/json',
          if (token != null) 'Authorization': 'Bearer $token',
        },
        body: jsonEncode({'liked_user_id': likedUserId}),
      );

      if (resp.statusCode == 200 || resp.statusCode == 201) {
        final body = jsonDecode(resp.body) as Map<String, dynamic>;
        final status = body['status'] as String?;

        if (status == 'matched') {
          if (context.mounted) {
            ScaffoldMessenger.of(context).showSnackBar(
              const SnackBar(content: Text("🎉 It's a match!")),
            );
          }
          onMatchedNavigate();
          return;
        }

        onLikedNavigate();
        return;
      }

      onRollback();
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('Like failed (${resp.statusCode})')),
        );
      }
    } catch (e) {
      onRollback();
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('Like error: $e')),
        );
      }
    }
  }
}

