import 'dart:async';
import 'dart:io';
import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';
import 'package:audioplayers/audioplayers.dart';
import 'package:path_provider/path_provider.dart';
import 'package:record/record.dart';
import '../services/api_service.dart';

/// Record → preview → post a voice-note like.
///
/// Flow:
///   idle      -> tap record -> recording
///   recording -> tap stop   -> stopped (preview available)
///   stopped   -> tap delete -> idle (fresh start)
///   stopped   -> tap post   -> posting -> upload + pop(true)
///   any       -> AppBar X   -> dispose + pop(false)
///
/// pop(true) means "voice like was posted, caller should treat as liked".
class VoiceLikeScreen extends StatefulWidget {
  final int targetUserId;
  final String targetUsername;

  const VoiceLikeScreen({
    super.key,
    required this.targetUserId,
    required this.targetUsername,
  });

  @override
  State<VoiceLikeScreen> createState() => _VoiceLikeScreenState();
}

enum _RecState { idle, recording, stopped, posting }

class _VoiceLikeScreenState extends State<VoiceLikeScreen> {
  final _recorder = AudioRecorder();
  final _player = AudioPlayer();

  _RecState _state = _RecState.idle;
  String? _path;
  Duration _elapsed = Duration.zero;
  Timer? _tick;
  bool _playing = false;
  StreamSubscription? _playerDoneSub;
  String _error = '';

  @override
  void initState() {
    super.initState();
    _playerDoneSub = _player.onPlayerComplete.listen((_) {
      if (mounted) setState(() => _playing = false);
    });
  }

  @override
  void dispose() {
    _tick?.cancel();
    _playerDoneSub?.cancel();
    _player.dispose();
    _recorder.dispose();
    super.dispose();
  }

  String _fmt(Duration d) {
    final m = d.inMinutes.toString().padLeft(2, '0');
    final s = (d.inSeconds % 60).toString().padLeft(2, '0');
    return '$m:$s';
  }

  Future<void> _startRecording() async {
    setState(() => _error = '');
    try {
      final allowed = await _recorder.hasPermission();
      if (!allowed) {
        setState(() => _error = 'Microphone permission denied');
        return;
      }
      // Web: path is ignored; mobile: write to temp dir.
      String? path;
      if (!kIsWeb) {
        final dir = await getTemporaryDirectory();
        path = '${dir.path}/voice_like_${DateTime.now().millisecondsSinceEpoch}.m4a';
      }
      await _recorder.start(
        const RecordConfig(encoder: AudioEncoder.aacLc, bitRate: 96000),
        path: path ?? 'voice_like.m4a',
      );
      _elapsed = Duration.zero;
      _tick?.cancel();
      _tick = Timer.periodic(const Duration(seconds: 1), (_) {
        if (!mounted) return;
        setState(() => _elapsed += const Duration(seconds: 1));
      });
      setState(() => _state = _RecState.recording);
    } catch (e) {
      setState(() => _error = 'Could not start recording: $e');
    }
  }

  Future<void> _stopRecording() async {
    _tick?.cancel();
    try {
      final p = await _recorder.stop();
      setState(() {
        _path = p;
        _state = _RecState.stopped;
      });
    } catch (e) {
      setState(() {
        _state = _RecState.idle;
        _error = 'Stop failed: $e';
      });
    }
  }

  Future<void> _deleteRecording() async {
    // Stop playback if any.
    if (_playing) {
      await _player.stop();
      _playing = false;
    }
    // Best-effort file cleanup on mobile.
    if (!kIsWeb && _path != null) {
      try {
        final f = File(_path!);
        if (await f.exists()) await f.delete();
      } catch (_) {}
    }
    setState(() {
      _path = null;
      _elapsed = Duration.zero;
      _state = _RecState.idle;
      _error = '';
    });
  }

  Future<void> _togglePreview() async {
    if (_path == null) return;
    try {
      if (_playing) {
        await _player.pause();
        setState(() => _playing = false);
      } else {
        if (kIsWeb) {
          await _player.play(UrlSource(_path!));
        } else {
          await _player.play(DeviceFileSource(_path!));
        }
        setState(() => _playing = true);
      }
    } catch (e) {
      setState(() => _error = 'Preview failed: $e');
    }
  }

  Future<void> _post() async {
    if (_path == null || _state == _RecState.posting) return;
    setState(() {
      _state = _RecState.posting;
      _error = '';
    });
    final result = await ApiService.postLikeWithVoice(
      likedUserId: widget.targetUserId,
      audioFilePath: _path!,
    );
    if (!mounted) return;
    if (result['success'] == true) {
      final status = result['status'] as String?;
      if (status == 'matched') {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text("🎉 It's a match!")),
        );
      }
      // Signal caller that the like was posted.
      Navigator.of(context).pop(true);
    } else {
      setState(() {
        _state = _RecState.stopped;
        _error = (result['message'] as String?) ??
            'Post failed (${result['statusCode'] ?? 'network'})';
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: const Color(0xFF0E0E0E),
      appBar: AppBar(
        backgroundColor: const Color(0xFF0E0E0E),
        leading: IconButton(
          icon: const Icon(Icons.close, color: Colors.white),
          tooltip: 'Cancel',
          onPressed: _state == _RecState.posting
              ? null
              : () => Navigator.of(context).pop(false),
        ),
        title: Text('Voice note to ${widget.targetUsername}',
            style: const TextStyle(fontSize: 16)),
      ),
      body: SafeArea(
        child: Padding(
          padding: const EdgeInsets.fromLTRB(24, 24, 24, 32),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              const SizedBox(height: 12),
              Text(
                _instructionText(),
                textAlign: TextAlign.center,
                style: const TextStyle(color: Colors.white70, fontSize: 14),
              ),
              const Spacer(),
              Center(child: _centerControl()),
              const SizedBox(height: 16),
              Center(
                child: Text(
                  _fmt(_elapsed),
                  style: const TextStyle(
                    color: Colors.white,
                    fontSize: 28,
                    fontWeight: FontWeight.w500,
                    fontFeatures: [FontFeature.tabularFigures()],
                  ),
                ),
              ),
              const Spacer(),
              if (_error.isNotEmpty) ...[
                Text(_error,
                    textAlign: TextAlign.center,
                    style: const TextStyle(color: Colors.redAccent, fontSize: 13)),
                const SizedBox(height: 12),
              ],
              _bottomActions(),
            ],
          ),
        ),
      ),
    );
  }

  String _instructionText() {
