// Post a "like" with a voice-note attachment (multipart/form-data).
// audioFilePath is a local path produced by the `record` package.
// Returns {'success': bool, 'status': 'matched'|'liked'|null,
//          'statusCode': int?, 'message': String?}
static Future<Map<String, dynamic>> postLikeWithVoice({
  required int likedUserId,
  required String audioFilePath,
}) async {
  try {
    final token = await _getToken();
    final uri = Uri.parse('$baseUrl/api/like');
    final req = http.MultipartRequest('POST', uri);
    if (token != null) req.headers['Authorization'] = 'Bearer $token';
    req.fields['liked_user_id'] = likedUserId.toString();

    if (kIsWeb) {
      // On web, the `record` package returns a path that http can reach.
      // If the multipart fromPath API fails on web, the BE session may
      // need to accept a data-URL payload instead — flag then.
      req.files.add(
        await http.MultipartFile.fromPath('voice_note', audioFilePath),
      );
    } else {
      final file = File(audioFilePath);
      final bytes = await file.readAsBytes();
      req.files.add(
        http.MultipartFile.fromBytes(
          'voice_note',
          bytes,
          filename: audioFilePath.split('/').last,
        ),
      );
    }

    final streamed = await req.send().timeout(const Duration(seconds: 30));
    final resp = await http.Response.fromStream(streamed);

    if (resp.statusCode == 200 || resp.statusCode == 201) {
      Map<String, dynamic> body;
      try {
        body = jsonDecode(resp.body) as Map<String, dynamic>;
      } catch (_) {
        body = {};
      }
      return {
        'success': true,
        'status': body['status'],
        'statusCode': resp.statusCode,
      };
    }

